CREATE OR REPLACE FUNCTION fpa_tel_get_group_frm_recp (as_memno char , ai_month integer , ai_year integer) RETURNS varchar AS $body$
DECLARE

  ls_group_name varchar(200);

BEGIN
  select  trim(both member_group_no) ||' : '||trim(both member_group_name)
  into STRICT    ls_group_name
  from    sc_mem_m_ucf_member_group
  where   (member_group_no =
          (
          SELECT  member_group_no
          from    sc_kep_t_monthly_receive
          where (receive_month = ai_month)
          and (receive_year = ai_year)
          and (membership_no = as_memno)
          ));
  return trim(both ls_group_name);
exception when others then CALL spa_dberror('fpa_tel_get_group_frm_recp');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
